func (this *GeminiCore) ParseOrder(order any, optionalArgs ...any) any {
	//
	// createOrder (private)
	//
	//      {
	//          "order_id":"106027397702",
	//          "id":"106027397702",
	//          "symbol":"etheur",
	//          "exchange":"gemini",
	//          "avg_execution_price":"2877.48",
	//          "side":"sell",
	//          "type":"exchange limit",
	//          "timestamp":"1650398122",
	//          "timestampms":1650398122308,
	//          "is_live":false,
	//          "is_cancelled":false,
	//          "is_hidden":false,
	//          "was_forced":false,
	//          "executed_amount":"0.014434",
	//          "client_order_id":"1650398121695",
	//          "options":[],
	//          "price":"2800.00",
	//          "original_amount":"0.014434",
	//          "remaining_amount":"0"
	//      }
	//
	// fetchOrder (private)
	//
	//      {
	//          "order_id":"106028543717",
	//          "id":"106028543717",
	//          "symbol":"etheur",
	//          "exchange":"gemini",
	//          "avg_execution_price":"0.00",
	//          "side":"buy",
	//          "type":"exchange limit",
	//          "timestamp":"1650398446",
	//          "timestampms":1650398446375,
	//          "is_live":true,
	//          "is_cancelled":false,
	//          "is_hidden":false,
	//          "was_forced":false,
	//          "executed_amount":"0",
	//          "client_order_id":"1650398445709",
	//          "options":[],
	//          "price":"2000.00",
	//          "original_amount":"0.01",
	//          "remaining_amount":"0.01"
	//      }
	//
	// fetchOpenOrders (private)
	//
	//      {
	//          "order_id":"106028543717",
	//          "id":"106028543717",
	//          "symbol":"etheur",
	//          "exchange":"gemini",
	//          "avg_execution_price":"0.00",
	//          "side":"buy",
	//          "type":"exchange limit",
	//          "timestamp":"1650398446",
	//          "timestampms":1650398446375,
	//          "is_live":true,
	//          "is_cancelled":false,
	//          "is_hidden":false,
	//          "was_forced":false,
	//          "executed_amount":"0",
	//          "client_order_id":"1650398445709",
	//          "options":[],
	//          "price":"2000.00",
	//          "original_amount":"0.01",
	//          "remaining_amount":"0.01"
	//      }
	//
	// cancelOrder (private)
	//
	//      {
	//          "order_id":"106028543717",
	//          "id":"106028543717",
	//          "symbol":"etheur",
	//          "exchange":"gemini",
	//          "avg_execution_price":"0.00",
	//          "side":"buy",
	//          "type":"exchange limit",
	//          "timestamp":"1650398446",
	//          "timestampms":1650398446375,
	//          "is_live":false,
	//          "is_cancelled":true,
	//          "is_hidden":false,
	//          "was_forced":false,
	//          "executed_amount":"0",
	//          "client_order_id":"1650398445709",
	//          "reason":"Requested",
	//          "options":[],
	//          "price":"2000.00",
	//          "original_amount":"0.01",
	//          "remaining_amount":"0.01"
	//      }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var timestamp any = this.SafeInteger(order, "timestampms")
	var amount any = this.SafeString(order, "original_amount")
	var remaining any = this.SafeString(order, "remaining_amount")
	var filled any = this.SafeString(order, "executed_amount")
	var status any = "closed"
	if IsTrue(GetValue(order, "is_live")) {
		status = "open"
	}
	if IsTrue(GetValue(order, "is_cancelled")) {
		status = "canceled"
	}
	var price any = this.SafeString(order, "price")
	var average any = this.SafeString(order, "avg_execution_price")
	var typeVar any = this.SafeString(order, "type")
	if IsTrue(IsEqual(typeVar, "exchange limit")) {
		typeVar = "limit"
	} else if IsTrue(IsTrue(IsEqual(typeVar, "market buy")) || IsTrue(IsEqual(typeVar, "market sell"))) {
		typeVar = "market"
	} else {
		typeVar = GetValue(order, "type")
	}
	var fee any = nil
	var marketId any = this.SafeString(order, "symbol")
	var symbol any = this.SafeSymbol(marketId, market)
	var id any = this.SafeString(order, "order_id")
	var side any = this.SafeStringLower(order, "side")
	var clientOrderId any = this.SafeString(order, "client_order_id")
	var optionsArray any = this.SafeValue(order, "options", []any{})
	var option any = this.SafeString(optionsArray, 0)
	var timeInForce any = "GTC"
	var postOnly any = false
	if IsTrue(!IsEqual(option, nil)) {
		if IsTrue(IsEqual(option, "immediate-or-cancel")) {
			timeInForce = "IOC"
		} else if IsTrue(IsEqual(option, "fill-or-kill")) {
			timeInForce = "FOK"
		} else if IsTrue(IsEqual(option, "maker-or-cancel")) {
			timeInForce = "PO"
			postOnly = true
		}
	}
	return this.SafeOrder(map[string]any{
		"id":                 id,
		"clientOrderId":      clientOrderId,
		"info":               order,
		"timestamp":          timestamp,
		"datetime":           this.Iso8601(timestamp),
		"lastTradeTimestamp": nil,
		"status":             status,
		"symbol":             symbol,
		"type":               typeVar,
		"timeInForce":        timeInForce,
		"postOnly":           postOnly,
		"side":               side,
		"price":              price,
		"triggerPrice":       nil,
		"average":            average,
		"cost":               nil,
		"amount":             amount,
		"filled":             filled,
		"remaining":          remaining,
		"fee":                fee,
		"trades":             nil,
	}, market)
}

